sp_widget.client_script:
api.controller = function(spUtil) {
  var c = this;


  var stateMap = {
    'register': 'Registered', 
    'registered': 'Registered', 
    'triage': 'Triage',
    'waiting': 'Waiting',
    'consultation': 'Consultation',
    'testing': 'Testing',
    'admitted': 'Admitted',
    'treatment': 'Treatment',
    'discharge_requested': 'Discharge Requested',
    'billing_pending': 'Billing Pending',
    'billing_issue': 'Billing Issue',
    'discharged': 'Discharged'
  };

  c.getStateLabel = function(stateValue) {
    if (!stateValue) return 'Unknown';
    var key = stateValue.toString().toLowerCase().trim();
    return stateMap[key] || stateValue;
  };

  c.showEditView = false;
  c.selectedPatient = {};

  c.searchText = '';
  c.filterState = '';
  c.currentPage = 1;
  c.pageSize = 6; 
  c.filteredPatients = [];
  c.totalPages = 1;

  c.getMin = function(a, b) { return Math.min(a, b); };

  c.updateFilters = function() {
    c.filteredPatients = c.data.myPatients.filter(function(p) {

      var matchText = true;
      if (c.searchText) {
        var term = c.searchText.toLowerCase();
        var nameMatch = p.full_name && p.full_name.toLowerCase().indexOf(term) !== -1;
        var numMatch = p.number && p.number.toLowerCase().indexOf(term) !== -1;
        matchText = nameMatch || numMatch;
      }

      var matchState = true;
      if (c.filterState) {

        var normalizedState = p.state ? p.state.toString().toLowerCase().trim() : '';
        if (normalizedState === 'registered') normalizedState = 'register';

        matchState = (normalizedState === c.filterState);
      }

      return matchText && matchState;
    });

    c.totalPages = Math.ceil(c.filteredPatients.length / c.pageSize) || 1;

    if (c.currentPage > c.totalPages) {
      c.currentPage = c.totalPages > 0 ? c.totalPages : 1;
    }
  };

  c.getPageArray = function() {
    var pages = [];
    for (var i = 1; i <= c.totalPages; i++) {
      pages.push(i);
    }
    return pages;
  };

  c.goToPage = function(pageNum) { c.currentPage = pageNum; };
  c.prevPage = function() { if (c.currentPage > 1) { c.currentPage--; } };
  c.nextPage = function() { if (c.currentPage < c.totalPages) { c.currentPage++; } };

  c.clearFilters = function() {
    c.searchText = '';
    c.filterState = '';
    c.updateFilters();
  };

  c.updateFilters();

  c.selectPatient = function(patient) {
    c.selectedPatient = patient; 
    c.showEditView = true; 

    spUtil.get('widget-form', {
      table: 'x_1954503_smartc_0_patient',
      sys_id: patient.sys_id,
      view: 'adminview2', 
      hideRelatedLists: true 
    }).then(function(response) {
      c.embeddedForm = response; 
    });
  };

  c.backToList = function() {
    c.selectedPatient = {};
    c.embeddedForm = null; 
    c.showEditView = false; 

    c.server.update().then(function() {
        c.updateFilters(); 
    });
  };
};

sp_widget.css:
.sc-doc-wrapper {
  font-family: 'Poppins', 'Inter', system-ui, sans-serif;
  color: #1e293b;
  padding: 20px;
  display: flex;
  flex-direction: column;
  min-height: calc(100vh - 40px);
}

.sc-doc-panel {
  background: #ffffff;
  border-radius: 16px;
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.03);
  margin-bottom: 24px;
  border: 1px solid #e2e8f0;
  display: flex;
  flex-direction: column;
  flex-grow: 1; 
}

.sc-doc-panel-header {
  padding: 20px 24px;
  border-bottom: 1px solid #f1f5f9;
  background-color: #ffffff;
}

.sc-doc-header-left { display: flex; align-items: center; gap: 16px; }
.sc-doc-panel-title { margin: 0; font-size: 18px; font-weight: 700; color: #1e293b;}
.text-primary { color: #1961ED; }

.sc-doc-header-divider { width: 1px; height: 24px; background-color: #e2e8f0; }


.sc-doc-btn-back {
  background: transparent; border: none; color: #64748b; font-size: 14px;
  font-weight: 600; display: flex; align-items: center; gap: 8px; cursor: pointer;
  padding: 0; transition: color 0.2s;
}
.sc-doc-btn-back:hover { color: #1961ED; }


.sc-doc-controls-header {
  padding: 20px 24px; background-color: #fbfcfe; border-bottom: 1px solid #f1f5f9;
}

.sc-doc-search-row { display: flex; gap: 16px; align-items: center; flex-wrap: wrap; }
.sc-doc-search-bar { flex: 1; min-width: 250px; position: relative; display: flex; align-items: center; }
.sc-doc-search-icon { position: absolute; left: 16px; color: #94a3b8; }

.sc-doc-input {
  width: 100%; height: 44px; padding: 0 16px 0 44px; border: 1px solid #cbd5e1; border-radius: 10px;
  font-size: 14px; color: #1e293b; transition: all 0.2s; font-family: inherit; box-sizing: border-box;
}

.sc-doc-select {
  height: 44px; padding: 0 36px 0 16px; border: 1px solid #cbd5e1; border-radius: 10px; font-size: 13px; font-weight: 500;
  color: #1e293b; background-color: #ffffff; transition: all 0.2s; font-family: inherit; cursor: pointer;
  appearance: none; -webkit-appearance: none;
  background-image: url("data:image/svg+xml;charset=UTF-8,%3csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24' fill='none' stroke='%2364748b' stroke-width='2' stroke-linecap='round' stroke-linejoin='round'%3e%3cpolyline points='6 9 12 15 18 9'%3e%3c/polyline%3e%3c/svg%3e");
  background-repeat: no-repeat; background-position: right 12px center; background-size: 16px; min-width: 160px;
}

.sc-doc-select:hover { border-color: #94a3b8; }
.sc-doc-input:focus, .sc-doc-select:focus { border-color: #1961ED; outline: none; box-shadow: 0 0 0 3px rgba(25, 97, 237, 0.1); }

.sc-doc-btn-clear {
  background: #ffffff; border: 1px solid #cbd5e1; color: #475569; padding: 0 20px; height: 44px; font-weight: 600; cursor: pointer; border-radius: 10px; font-size: 13px; transition: 0.2s; white-space: nowrap;
}
.sc-doc-btn-clear:hover { background: #f8fafc; border-color: #94a3b8; color: #1e293b; }

.sc-doc-btn-link {
  background: #eff6ff; border: 1px solid #bfdbfe; color: #1d4ed8; padding: 6px 14px; border-radius: 8px; font-weight: 600; font-size: 12px; cursor: pointer; transition: 0.2s;
}
.sc-doc-btn-link:hover { background: #1961ED; color: #ffffff; border-color: #1961ED; }

/* --- Table Beautification --- */
.sc-doc-table-wrapper { width: 100%; overflow-x: auto; }
.sc-doc-table { width: 100%; border-collapse: collapse; text-align: left; }

.sc-doc-table th { 
  background-color: #f8fafc; color: #64748b; font-size: 12px; font-weight: 700; 
  text-transform: uppercase; padding: 16px 24px; border-bottom: 1px solid #e2e8f0; letter-spacing: 0.5px;
}

.sc-doc-table td { padding: 16px 24px; border-bottom: 1px solid #f1f5f9; font-size: 14px; vertical-align: middle;}
.sc-doc-table tbody tr { transition: background-color 0.2s; }
.sc-doc-table tbody tr:hover { background-color: #f8fafc; }

.sc-doc-fw-bold { font-weight: 600; }
.sc-doc-text-muted { color: #64748b; font-size: 13px; }
.sc-doc-text-capitalize { text-transform: capitalize; }

/* Badges inside Table */
.sc-doc-severity-badge, .sc-doc-state-badge {
  padding: 4px 10px; border-radius: 20px; font-size: 11px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.5px; display: inline-block; white-space: nowrap;
}

.severity-critical { background: #fee2e2; color: #b91c1c; }
.severity-high { background: #ffedd5; color: #c2410c; }
.severity-moderate { background: #eff6ff; color: #1d4ed8; }
.severity-low { background: #f1f5f9; color: #475569; }


.state-register, .state-registered { background: #f1f5f9; color: #475569; } 
.state-triage { background: #f3e8ff; color: #6d28d9; } 
.state-waiting { background: #fef3c7; color: #b45309; }
.state-consultation { background: #e0f2fe; color: #0369a1; } 
.state-testing { background: #e0e7ff; color: #4338ca; }
.state-admitted { background: #dbeafe; color: #1d4ed8; } 
.state-treatment { background: #fae8ff; color: #a21caf; } 
.state-discharge_requested { background: #ffedd5; color: #c2410c; } 
.state-billing_pending { background: #fce7f3; color: #be185d; } 
.state-billing_issue { background: #fee2e2; color: #b91c1c; } 
.state-discharged { background: #dcfce7; color: #15803d; } 


.sc-doc-pagination-wrapper { 
  display: flex; justify-content: space-between; align-items: center; padding: 20px 24px; border-top: 1px solid #e2e8f0; background: #fff;
  margin-top: auto; 
}
.sc-doc-pagination-info { font-size: 13px; color: #64748b; font-weight: 500; }
.sc-doc-pagination-controls { display: flex; align-items: center; gap: 4px;}
.sc-doc-page-numbers { display: flex; gap: 4px; margin: 0 4px; }

.sc-doc-btn-page, .sc-doc-btn-page-num {
  background: #ffffff; border: 1px solid #e2e8f0; color: #475569; padding: 6px; border-radius: 8px; font-size: 13px; font-weight: 600;
  cursor: pointer; transition: all 0.2s; font-family: inherit; display: flex; align-items: center; justify-content: center; min-width: 32px; height: 32px;
}
.sc-doc-btn-page:hover:not([disabled]), .sc-doc-btn-page-num:hover { background: #f1f5f9; color: #1e293b; }
.sc-doc-btn-page[disabled] { opacity: 0.3; cursor: not-allowed; }
.sc-doc-btn-page-num.active { background: #1961ED; color: #ffffff; border-color: #1961ED;}

.sc-doc-empty-status { padding: 40px 20px; text-align: center; color: #64748b; font-weight: 500; margin-bottom: auto;} 

.sc-doc-panel-body { padding: 24px; flex-grow: 1; }

.sc-doc-profile-card {
  background: #ffffff; border: 1px solid #e2e8f0; border-top: 4px solid #1961ED; border-radius: 12px; padding: 24px; box-shadow: 0 4px 15px rgba(0, 0, 0, 0.02); margin-bottom: 30px;
}

.sc-doc-info-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 24px 20px; }
.sc-doc-info-block { display: flex; flex-direction: column; gap: 6px; }

.sc-doc-info-block label { 
  font-size: 11px; color: #94a3b8; text-transform: uppercase; font-weight: 700; letter-spacing: 0.5px; margin: 0; display: flex; align-items: center; gap: 6px;
}
.sc-doc-info-block label i { font-size: 13px; opacity: 0.8; }
.sc-doc-info-block p { margin: 0; font-size: 15px; font-weight: 600; color: #1e293b; }



.sc-doc-embedded-form { 
  background: #ffffff; 
  border-radius: 12px; 
  padding: 10px; 
}


.sc-doc-embedded-form label,
.sc-doc-embedded-form .control-label,
.sc-doc-embedded-form .form-group > label {
  font-size: 13px !important;
  font-weight: 600 !important;
  color: #1e293b !important;
  margin-bottom: 8px !important;
  text-transform: none !important;
  letter-spacing: normal !important;
}

.sc-doc-embedded-form .form-control,
.sc-doc-embedded-form input[type="text"],
.sc-doc-embedded-form input[type="number"],
.sc-doc-embedded-form select,
.sc-doc-embedded-form textarea {
  border: 1px solid #94a3b8 !important;
  border-radius: 6px !important;
  padding: 8px 12px !important;
  font-size: 14px !important;
  color: #1e293b !important;
  background-color: #f8fafc !important;
  box-shadow: 0 1px 2px rgba(0,0,0,0.02) !important;
  width: 100% !important;
  box-sizing: border-box !important;
}

.sc-doc-embedded-form .form-control:not(textarea),
.sc-doc-embedded-form input:not(textarea),
.sc-doc-embedded-form select {
  height: 40px !important;
}

.sc-doc-embedded-form textarea {
  height: auto !important;
  min-height: 80px !important;
}

.sc-doc-embedded-form .input-group {
  display: flex !important;
  width: 100% !important;
  border: 1px solid #94a3b8 !important; /* Move border to wrapper */
  border-radius: 6px !important;
  overflow: hidden !important; /* Hide button spillage */
  background: #f8fafc !important;
}


.sc-doc-embedded-form .input-group input.form-control,
.sc-doc-embedded-form .input-group .form-control {
  border: none !important;
  border-radius: 0 !important;
  margin: 0 !important;
  flex: 1 1 auto !important;
  height: 38px !important;
  background: transparent !important;
  box-shadow: none !important;
  min-width: 0 !important;
}

.sc-doc-embedded-form .input-group-btn {
  display: flex !important;
  flex: 0 0 44px !important; 
  background-color: #f1f5f9 !important;
  border: none !important;
  border-left: 1px solid #cbd5e1 !important; 
  padding: 0 !important;
  margin: 0 !important;
}

.sc-doc-embedded-form .input-group-btn .btn,
.sc-doc-embedded-form .input-group-btn button,
.sc-doc-embedded-form .input-group-btn a {
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
  border: none !important;
  background: transparent !important;
  width: 100% !important;
  height: 100% !important;
  padding: 0 !important;
  margin: 0 !important;
  color: #475569 !important;
  box-shadow: none !important;
  border-radius: 0 !important;
}


.sc-doc-embedded-form .form-control:hover,
.sc-doc-embedded-form .input-group:hover {
  border-color: #64748b !important;
}

.sc-doc-embedded-form .form-control:focus,
.sc-doc-embedded-form .input-group:focus-within {
  border-color: #1961ED !important;
  background-color: #ffffff !important;
  box-shadow: 0 0 0 3px rgba(25, 97, 237, 0.15) !important;
  outline: none !important;
}


.sc-doc-wrapper .btn-primary { 
  background: #1961ED !important; border: none !important; color: #fff !important; 
  padding: 8px 16px !important; border-radius: 6px !important; font-weight: 600 !important; cursor: pointer; 
}

.sc-doc-wrapper .btn-default:not(.sc-doc-btn-default) { 
  background: #ffffff !important; border: 1px solid #94a3b8 !important; color: #1e293b !important; 
  padding: 8px 16px !important; border-radius: 6px !important; font-weight: 600; cursor: pointer; 
}

sp_widget.script:
(function() {
    var userId = gs.getUserID();

    data.myPatients = [];
    var pGR = new GlideRecord('x_1954503_smartc_0_patient');



    pGR.orderByDesc('sys_created_on');
    pGR.query();

    while (pGR.next()) {
        data.myPatients.push({
            sys_id: pGR.getUniqueValue(),
            number: pGR.getValue('number') || 'N/A', 
            full_name: pGR.getValue('full_name') || 'Unknown',
            age: pGR.getValue('age') || '--',
            gender: pGR.getValue('gender') || '--', // Added Gender
            email: pGR.getValue('email') || '--',   // Added Email
            department: pGR.getDisplayValue('medical_department') || 'Unassigned',
            state: pGR.getValue('state') || 'waiting',
            severity: pGR.getValue('severity') || 'low',
            symptoms: pGR.getValue('symptoms') || '',

            assigned_doctor: pGR.getDisplayValue('assigned_doctor') || 'Pending',
            assigned_nurse: pGR.getDisplayValue('u_assigned_nurse') || 'Pending'
        });
    }
})();
